+        assert!(resp.note.contains("ruqu-core::optimizer::fuse_gates"));
+        assert_eq!(resp.gate_count_before, Some(2));
+        assert_eq!(resp.gate_count_after, Some(2));
+        assert_eq!(resp.is_clifford, Some(true));
